/* ══════════════════════════════════════════════
   MÓDULO 1: SANITIZACIÓN cleanText() / sanitize()
   ══════════════════════════════════════════════ */
/* ── toTitleCase: capitaliza cada palabra preservando tildes ── */
function toTitleCase(str) {
  return String(str).toLowerCase()
    .replace(/(?:^|\s|-)([a-záéíóúüñ])/g, c => c.toUpperCase());
}

const _ENT = {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":"&#x27;",'/':'&#x2F;','`':'&#x60;','=':'&#x3D;'};
const sanitize   = s => String(s??'').replace(/[&<>"'`=\/]/g, c => _ENT[c]);
const desanitize = s => s.replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&#x27;/g,"'");
/** cleanText: elimina tildes, eñes, comillas, etiquetas HTML.
 *  Resuelve nombres como O'Connor, García que rompían QR/PPTX */
const cleanText = s => String(s??'').normalize('NFD')
  .replace(/[\u0300-\u036f]/g,'')
  .replace(/[<>"'`\/\\]/g,'')
  .trim().toUpperCase();

/* ══════════════════════════════════════════════
   MÓDULO 2: TOAST (reemplaza alert() bloqueante)
   ══════════════════════════════════════════════ */
function toast(msg, tipo='info', dur=3500) {
  const tc = document.getElementById('toastContainer'); if(!tc) return;
  const el = document.createElement('div');
  el.className = 'toast t-' + tipo;
  el.textContent = msg;
  tc.appendChild(el);
  setTimeout(() => { el.style.opacity='0'; el.style.transition='opacity .3s'; setTimeout(()=>el.remove(),300); }, dur);
}

