/* ══════════════════════════════════════════════
   MÓDULO 4: AUDITORÍA INTERNA (Ctrl+Shift+A)
   ══════════════════════════════════════════════ */
function audit(msg, tipo='INFO') {
  const ts = new Date().toLocaleTimeString('es-VE',{hour:'2-digit',minute:'2-digit',second:'2-digit',timeZone:'America/Caracas'});
  if(EC.auditLog.length >= 200) EC.auditLog.shift(); // circular buffer
  EC.auditLog.push({ts, msg, tipo, usr: EC.profName||'Sistema'});
  const ul = document.getElementById('auditList'); if(!ul) return;
  const d = document.createElement('div');
  d.className = 'audit-row';
  const c = {OK:'#4ade80',ERROR:'#f87171',WARN:'#fbbf24',INFO:'#7dd3fc'}[tipo]||'#7dd3fc';
  d.innerHTML = `<span class="audit-ts">${ts}</span><span style="color:${c}">[${tipo}] ${sanitize(EC.profName||'S')}: ${sanitize(msg)}</span>`;
  ul.insertBefore(d, ul.firstChild);
}
const openAudit  = () => { const p=document.getElementById('auditPanel'); if(p) p.classList.add('open'); };
const closeAudit = () => { const p=document.getElementById('auditPanel'); if(p) p.classList.remove('open'); };
function exportAudit() {
  const txt = EC.auditLog.map(e=>`[${e.ts}][${e.tipo}] ${e.usr}: ${e.msg}`).join('\n');
  const fecha = new Date().toISOString().slice(0,10);
  const firma = `\n\n--- FIRMA DIGITAL ---\nDocente: ${EC.profName}\nHash: ${btoa(String(txt.length))}\nTotal entradas: ${EC.registros.length}`;
  const a = document.createElement('a');
  a.href = URL.createObjectURL(new Blob([txt+firma],{type:'text/plain'}));
  a.download = `auditoria_${fecha}.txt`;
  a.click();
}
document.addEventListener('keydown', e => { if(e.ctrlKey && e.shiftKey && e.key==='A'){ e.preventDefault(); openAudit(); } });

/* ══════════════════════════════════════════════
   MÓDULO 5: PERSISTENCIA — localStorage eficiente
   Solo guarda ID+hora+tipo (no nombres completos).
   Base64 ofuscado + checksum anti-manipulación.
   ══════════════════════════════════════════════ */
const LS_KEY   = 'ec5_jornada';
const LS_LISTA = 'ec5_lista';   // persiste todo el año escolar

/* ── Almacenamiento seguro ─────────────────────────────────────────────
   En Android (APK): usa window.AndroidStorage — cifrado AES-256-GCM
   via EncryptedSharedPreferences (Kotlin bridge).
   En navegador web: usa localStorage como siempre.
   El wrapper normaliza getItem para que devuelva null (no "null" string).
   ──────────────────────────────────────────────────────────────────── */
const Store = (() => {
  if (typeof window !== 'undefined' && window.AndroidStorage) {
    return {
      setItem:    (k, v) => window.AndroidStorage.setItem(String(k), String(v)),
      getItem:    (k)    => { const v = window.AndroidStorage.getItem(String(k)); return (v === 'null' || v == null) ? null : v; },
      removeItem: (k)    => window.AndroidStorage.removeItem(String(k)),
    };
  }
  return localStorage;
})();

function guardarLista() {
  try {
    if(!EC.alumnos.length) return;
    const payload = { alumnos: EC.alumnos, fecha: new Date().toLocaleDateString('es-VE',{timeZone:'America/Caracas'}) };
    Store.setItem(LS_LISTA, JSON.stringify(payload));
  } catch(e) { /* QuotaExceeded */ }
}

function cargarListaGuardada() {
  try {
    const raw = Store.getItem(LS_LISTA);
    return raw ? JSON.parse(raw) : null;
  } catch(e) { return null; }
}

async function guardarSesion() {
  try {
    const hoy = new Date().toDateString();
    const payload = {
      fecha:    hoy,
      prof:     EC.profName,
      hora:     EC.horaEntrada,
      estado:   EC.jornadaEstado,
      retardos: EC.histRetardos,
      // Solo id+hora+tipo — 80% menos memoria que guardar nombres
      regs: EC.registros.map(r => ({i:r.id, h:r.hora, t:r.tipo, tar:r.tardio||false, f:r.fecha, ap:r.apellido, nm:r.nombre, nr:r.nro})),
      alumnos: EC.alumnos.length ? EC.alumnos : undefined,
    };
    const enc = btoa(unescape(encodeURIComponent(JSON.stringify(payload))));
    const cs  = btoa(String(enc.length)); // checksum
    Store.setItem(LS_KEY, JSON.stringify({d:enc, cs}));
    actualizarStatusBar();
  } catch(e) { /* QuotaExceeded — continuar sin persistencia */ }
}

async function cargarSesion() {
  try {
    const raw = Store.getItem(LS_KEY);
    if(!raw) return null;
    const obj = JSON.parse(raw);
    // Validar checksum — detecta manipulación por consola del navegador
    if(btoa(String(obj.d.length)) !== obj.cs) {
      toast('⚠️ Sesión corrompida detectada — datos restaurados a estado íntegro', 'warn', 6000);
      audit('CHECKSUM INVÁLIDO — posible manipulación de localStorage', 'ERROR');
      Store.removeItem(LS_KEY);
      return null;
    }
    return JSON.parse(decodeURIComponent(escape(atob(obj.d))));
  } catch(e) {
    audit('Error al leer sesión: ' + e.message, 'ERROR');
    return null;
  }
}

function actualizarStatusBar() {
  const bytes = new Blob([Store.getItem(LS_KEY)||'']).size;
  const set = (id, val) => { const el=document.getElementById(id); if(el) el.textContent=val; };
  set('sbStore', 'LS: ' + (bytes/1024).toFixed(1) + 'KB');
  set('sbProf',  EC.profName || '—');
  // sbHora hidden per requirement
  // Fecha con formato venezolano legible
  set('sbFecha', new Date().toLocaleDateString('es-VE', {weekday:'short', day:'2-digit', month:'short', timeZone:'America/Caracas'}));
  actualizarBannerJornada();
}

/* ══════════════════════════════════════════════
   MÓDULO 6: NORMALIZACIÓN TELEMÁTICA
   ══════════════════════════════════════════════ */
const normID = s => cleanText(s).replace(/[Nn]/g, c => c==='Ñ'||c==='ñ'?'N':c).replace(/[^A-Z0-9]/g,'');

const normGrado = v => {
  const m = {PRIMERO:'1',SEGUNDO:'2',TERCERO:'3',CUARTO:'4',QUINTO:'5',SEXTO:'6'};
  const s = String(v).toUpperCase();
  for(const[k,val] of Object.entries(m)) if(s.includes(k)) return val;
  const d = s.match(/\d+/);
  return d ? d[0] : '?';
};

function genCarnetID(nro, grado, sec, ape, nom) {
  const g  = normGrado(grado);
  const ss = normID(sec).replace(/^SECCION/,'').slice(0,2) || 'X';
  const np = String(Math.max(1, parseInt(nro)||0)).padStart(3,'0');
  const ia = normID(ape).slice(0,2) || 'XX';
  const in_= normID(nom).slice(0,1) || 'X';
  return `${g}${ss}-${np}-${ia}${in_}`;
}

/* ══════════════════════════════════════════════
   MÓDULO 7: BUSCADOR DIFUSO (Levenshtein)
   Umbral dinámico: ≤2 chars = startsWith,
   ≥3 chars = distancia de edición con debounce.
   ══════════════════════════════════════════════ */
function levenshtein(a, b) {
  const m=a.length, n=b.length;
  const dp=Array.from({length:m+1},(_,i)=>Array.from({length:n+1},(_,j)=>i===0?j:j===0?i:0));
  for(let i=1;i<=m;i++) for(let j=1;j<=n;j++)
    dp[i][j]=a[i-1]===b[j-1]?dp[i-1][j-1]:1+Math.min(dp[i-1][j],dp[i][j-1],dp[i-1][j-1]);
  return dp[m][n];
}
function fuzzyMatch(texto, query) {
  if(!query) return true;
  const t=texto.toLowerCase(), q=query.toLowerCase();
  if(q.length<=2) return t.startsWith(q);
  if(t.includes(q)) return true;
  const umbral=Math.floor(q.length*.38)+1;
  for(let i=0;i<=t.length-q.length+umbral;i++)
    if(levenshtein(t.slice(i,i+q.length),q)<=umbral) return true;
  return false;
}
let _fuzzyT=null;
function filtrarDifuso() { clearTimeout(_fuzzyT); _fuzzyT=setTimeout(renderTablaGlobal,160); }
