/* ══════════════════════════════════════════════
   MÓDULO 9: CARGA EXCEL — Detección por nombre
   No usa posición numérica — resuelve columna extra.
   ══════════════════════════════════════════════ */
function detectarColumnas(rawData) {
  const keys = Object.keys(rawData[0]||{});
  const norm  = s => String(s).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
  const find  = aliases => keys.find(k=>aliases.some(a=>norm(k).includes(a))) || null;
  return {
    nro:     find(['nro','n°','num','#','orden','numero']),
    apellido:find(['apellido','ape','paterno','primer apellido']),
    nombre:  find(['nombre','nom','primer nombre']),
    grado:   find(['grado','grad','nivel','año']),
    seccion: find(['secci','sec','grupo','sala']),
    keys,
  };
}

function mostrarModalColumnas(raw, map) {
  EC._rawPend = raw; EC._mapPend = map;
  const keys  = map.keys;
  // Tomar las primeras 4 filas reales del Excel (sin encabezados duplicados)
  const muestra = raw.slice(0, 4);

  // Construir tabla de vista previa con datos reales numerados
  const grid = document.getElementById('colMapGrid'); if(!grid) return;

  // Vista previa de datos: columnas × filas
  const previewHTML = `
    <div style="overflow-x:auto;margin-bottom:14px;">
      <p style="font-size:11px;color:var(--t3);margin-bottom:8px;">
        📊 Datos detectados en el Excel — ${raw.length} filas · ${keys.length} columnas
      </p>
      <table style="width:100%;border-collapse:collapse;font-size:11px;">
        <thead>
          <tr>
            <th style="background:var(--bg3);padding:6px 9px;text-align:left;color:var(--t3);border:1px solid var(--border);font-size:10px;">#</th>
            ${keys.map((k,ci) => `<th style="background:var(--bg3);padding:6px 9px;text-align:left;color:var(--az);border:1px solid var(--border);font-size:10px;white-space:nowrap;">
              Col. ${ci+1}<br><span style="color:var(--t3);font-weight:400;">${sanitize(String(k).slice(0,16))}</span>
            </th>`).join('')}
          </tr>
        </thead>
        <tbody>
          ${muestra.map((row, ri) => `<tr>
            <td style="padding:5px 9px;border:1px solid var(--border);color:var(--t3);font-family:var(--mono);font-size:10px;">${ri+1}</td>
            ${keys.map(k => `<td style="padding:5px 9px;border:1px solid var(--border);color:var(--t1);max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${sanitize(String(row[k]??'').slice(0,20))}</td>`).join('')}
          </tr>`).join('')}
        </tbody>
      </table>
    </div>`;

  // Controles de mapeo con los datos enumerados
  const campos = [
    {id:'nro',     lbl:'Nro de orden', ico:'#',  det:map.nro,     req:false},
    {id:'apellido',lbl:'Apellidos',    ico:'👤', det:map.apellido, req:true},
    {id:'nombre',  lbl:'Nombres',      ico:'✏️', det:map.nombre,   req:true},
    {id:'grado',   lbl:'Grado',        ico:'🎓', det:map.grado,    req:false},
    {id:'seccion', lbl:'Sección',      ico:'🏫', det:map.seccion,  req:false},
  ];

  const controlesHTML = `
    <div style="display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-bottom:12px;">
      ${campos.map(c => `
        <div style="background:var(--bg2);border:1px solid ${c.req?'rgba(14,165,233,.4)':'var(--border)'};border-radius:var(--rs);padding:9px;">
          <div style="font-size:11px;color:${c.req?'var(--az)':'var(--t2)'};font-weight:700;margin-bottom:4px;">${c.ico} ${sanitize(c.lbl)}${c.req?' *':''}</div>
          <select id="sel-${c.id}" style="background:var(--bg3);color:var(--t1);border:1px solid var(--border);border-radius:6px;padding:5px;width:100%;font-size:11px;">
            <option value="">— sin asignar —</option>
            ${keys.map((k,ci) => `<option value="${sanitize(k)}"${c.det===k?' selected':''}>Col. ${ci+1} · ${sanitize(String(k).slice(0,14))}</option>`).join('')}
          </select>
          ${c.det ? `<div style="font-size:9px;color:var(--vd);margin-top:3px;">✅ Auto: Col. ${keys.indexOf(c.det)+1}</div>` : `<div style="font-size:9px;color:var(--am);margin-top:3px;">${c.req?'⚠️ Requerido':''}</div>`}
        </div>`).join('')}
    </div>`;

  grid.innerHTML = previewHTML + controlesHTML;

  const falt = ['apellido','nombre'].filter(f=>!map[f]);
  const warn = document.getElementById('colMapWarn'); if(warn)
    warn.innerHTML = falt.length
      ? `<div class="alert al-warn">⚠️ No se detectaron: <strong>${falt.map(f=>f==='apellido'?'Apellidos':'Nombres').join(', ')}</strong> — selecciona la columna correcta arriba.</div>`
      : `<div class="alert al-ok">✅ Columnas detectadas. Confirma el mapeo y procede.</div>`;
  const mc = document.getElementById('mColMap'); if(mc) mc.classList.remove('hidden');
}
function cancelarColMap() {
  const m = document.getElementById('mColMap'); if(m) m.classList.add('hidden');
  const fi = document.getElementById('fileInput'); if(fi) fi.value='';
  EC._rawPend=null; EC._mapPend=null;
}
function confirmarColMap() {
  const get = id => document.getElementById('sel-'+id)?.value||null;
  const m = {
    nro:get('nro'), apellido:get('apellido'), nombre:get('nombre'),
    grado:get('grado'), seccion:get('seccion'), keys:EC._mapPend?.keys||[],
  };
  if(!m.apellido||!m.nombre){ toast('⚠️ Apellidos y Nombres son obligatorios','warn'); return; }
  const mc = document.getElementById('mColMap'); if(mc) mc.classList.add('hidden');
  procesarExcel(EC._rawPend, m);
}

function cargarArchivoExcel(event, target) {
  const file = event?.target?.files?.[0]; if(!file) return;
  const reader = new FileReader();
  reader.onload = e => {
    try {
      const wb  = XLSX.read(e.target.result, {type:'binary'});
      const ws  = wb.Sheets[wb.SheetNames[0]];
      const raw = XLSX.utils.sheet_to_json(ws, {defval:''});
      if(!raw.length){ toast('⚠️ Archivo vacío','warn'); return; }
      const map = detectarColumnas(raw);
      // Si falta apellido o nombre → mostrar modal de mapeo
      if(!map.apellido||!map.nombre||!map.grado) mostrarModalColumnas(raw, map);
      else procesarExcel(raw, map);
      if(target==='app2') {
        const al = document.getElementById('alertSinLista'); if(al) al.style.display='none';
      }
    } catch(err) { toast('⚠️ Error al leer: '+err.message,'err'); audit('Error Excel: '+err.message,'ERROR'); }
  };
  reader.readAsBinaryString(file);
}

/* ══════════════════════════════════════════════
   MÓDULO 10: PROCESAMIENTO EXCEL
   cleanText() + sanitize() en cada campo.
   Set() para detectar duplicados en tiempo real.
   ══════════════════════════════════════════════ */
function procesarExcel(rawData, map) {
  const esEnc = r => Object.values(r).map(x=>String(x).toLowerCase()).some(x=>x.includes('apellido')||x==='nro'||x==='nombre');
  const rows  = rawData.filter(r=>!esEnc(r)).filter(r=>{
    const a=r[map.apellido]||r[map.keys?.[2]]||'';
    const n=r[map.nombre]  ||r[map.keys?.[3]]||'';
    return String(a).trim()&&String(n).trim();
  });
  if(!rows.length){ toast('⚠️ No se encontraron alumnos válidos. Verifica el Excel.','warn'); return; }

  const idSet=new Set(), dups=[];
  const lista = rows.map((r,idx) => {
    const nro     = Math.max(1, parseInt(r[map.nro]||r[map.keys?.[0]]||idx+1)||idx+1);
    // Versión limpia para generar el ID (sin tildes, sin caracteres especiales)
    const apellidoClean = cleanText(String(r[map.apellido]||r[map.keys?.[2]]||''));
    const nombreClean   = cleanText(String(r[map.nombre]  ||r[map.keys?.[3]]||''));
    // Versión original para mostrar en pantalla (solo sanitizar HTML, conservar tildes y capitalización)
    const apellido = sanitize(toTitleCase(String(r[map.apellido]||r[map.keys?.[2]]||'').trim()));
    const nombre   = sanitize(toTitleCase(String(r[map.nombre]  ||r[map.keys?.[3]]||'').trim()));
    const grado    = normGrado(r[map.grado]  ||r[map.keys?.[4]]||'6');
    const seccion  = sanitize(cleanText(String(r[map.seccion] ||r[map.keys?.[5]]||'C')));
    const id       = genCarnetID(nro, grado, seccion, apellidoClean, nombreClean);
    if(idSet.has(id)) dups.push({apellido,nombre,id});
    else idSet.add(id);
    if(EC.histRetardos[id]===undefined) EC.histRetardos[id]=0;
    return {nro, apellido, nombre, grado, seccion, id};
  });

  EC.alumnos = lista;

  // Mostrar alerta de duplicados
  const alertD = document.getElementById('alertDuplicados');
  if(dups.length>0 && alertD) {
    alertD.classList.remove('hidden');
    alertD.textContent = `⚠️ ${dups.length} ID(s) duplicados detectados con Set(): ${dups.map(d=>d.apellido).join(', ')} — revisa el Excel`;
    toast(`⚠️ ${dups.length} IDs duplicados detectados`,'warn',7000);
    audit(`IDs duplicados: ${dups.map(d=>d.id).join(', ')}`,'WARN');
  } else if(alertD) alertD.classList.add('hidden');

  // Mostrar resultados
  renderPreviewExcel();
  document.getElementById('excelPreview')?.classList.remove('hidden');
  document.getElementById('uploadZone')?.style?.setProperty('display','none');
  const em = document.getElementById('excelMsg');
  if(em) em.textContent = `✅ ${EC.alumnos.length} alumnos · cleanText() aplicado · Columnas validadas por nombre`;

  renderListas(); renderTablaGlobal(); renderDashboard(); actualizarContadores();
  guardarSesion();
  guardarLista();
  toast(`✅ ${EC.alumnos.length} alumnos cargados correctamente`, 'ok');
  audit(`Excel cargado: ${EC.alumnos.length} alumnos`, 'OK');
}

function renderPreviewExcel() {
  const t = document.getElementById('previewTable'); if(!t) return;
  t.innerHTML = `<table>
    <thead><tr><th>Nro</th><th>Apellidos</th><th>Nombres</th><th>Grado</th><th>Sección</th><th>ID Carnet</th></tr></thead>
    <tbody>
    ${EC.alumnos.slice(0,8).map(a=>`<tr>
      <td>${a.nro}</td>
      <td><strong>${a.apellido}</strong></td>
      <td>${a.nombre}</td>
      <td><span class="badge b-az">${a.grado}°</span></td>
      <td><span class="badge b-nj">${a.seccion}</span></td>
      <td><code class="mono">${a.id}</code></td>
    </tr>`).join('')}
    ${EC.alumnos.length>8?`<tr><td colspan="6" style="text-align:center;color:var(--t3);padding:8px;">…y ${EC.alumnos.length-8} alumnos más</td></tr>`:''}
    </tbody></table>`;
}

function resetExcel() { cambiarLista(); }

function cambiarLista() {
  const n = EC.alumnos.length;
  if(n && !confirm(`⚠️ ¿Cambiar la lista del plantel?\n\nSe eliminarán los ${n} alumnos actuales y deberás cargar el Excel del nuevo año o sección.\n\nLos registros de asistencia del día no se pierden.`)) return;
  EC.alumnos = [];
  Store.removeItem(LS_LISTA);
  document.getElementById('excelPreview')?.classList.add('hidden');
  const uz = document.getElementById('uploadZone'); if(uz) uz.style.display='';
  const qs = document.getElementById('qrSection'); if(qs) qs.classList.add('hidden');
  const fi = document.getElementById('fileInput'); if(fi) fi.value='';
  renderTablaGlobal(); actualizarContadores();
  audit('Lista del plantel eliminada — cambio de año/sección', 'WARN');
  toast('📋 Lista eliminada. Carga el Excel del nuevo año o sección.', 'warn', 5000);
}

function exportarBackup() {
  const fecha=new Date().toISOString();
  const payload={version:'5.0',fecha,autor:EC.profName,
    alumnos:EC.alumnos.map(({apellido,nombre,...r})=>({...r,a:'[ENC]',n:'[ENC]'})),
    registros:EC.registros.map(({apellido,nombre,...r})=>({...r})),
    retardos:EC.histRetardos,
    firma:btoa(fecha+EC.profName+EC.alumnos.length)};
  const a=document.createElement('a');
  a.href=URL.createObjectURL(new Blob([JSON.stringify(payload,null,2)],{type:'application/json'}));
  a.download=`backup_${fecha.slice(0,10)}.ecbackup`;
  a.click();
  audit('Backup cifrado exportado','OK');
}

/* ══════════════════════════════════════════════
   MÓDULO 11: AUDIO — desbloqueo en botón login
   AudioContext creado en click del usuario.
   Tono diferenciado: OK / TARDÍO / WARN / ERROR
   ══════════════════════════════════════════════ */
function desbloquearAudio() {
  try {
    const ctx=new(window.AudioContext||window.webkitAudioContext)();
    const o=ctx.createOscillator(),g=ctx.createGain();
    g.gain.value=0; o.connect(g); g.connect(ctx.destination);
    o.start(); o.stop(ctx.currentTime+0.001);
    audit('AudioContext desbloqueado en botón Iniciar Sesión','OK');
  } catch(e){ /* continuar sin audio */ }
}

function playTono(tipo) {
  try {
    const ctx=new(window.AudioContext||window.webkitAudioContext)();
    if(ctx.state==='suspended') ctx.resume();
    const gain=ctx.createGain(); gain.connect(ctx.destination);
    const t=ctx.currentTime;
    const note=(f,d,dur,vol=.2,shape='sine')=>{
      const o=ctx.createOscillator(); o.type=shape; o.frequency.value=f; o.connect(gain);
      gain.gain.setValueAtTime(0,t+d);
      gain.gain.linearRampToValueAtTime(vol,t+d+.03);
      gain.gain.linearRampToValueAtTime(0,t+d+dur);
      o.start(t+d); o.stop(t+d+dur+.02);
    };
    if(tipo==='ok')   { note(261.63,0,.18,.22,'triangle'); note(329.63,.10,.18,.22,'triangle'); note(392,.20,.22,.22,'triangle'); }
    else if(tipo==='tard'){ note(349.23,0,.16,.18); note(392,.13,.18,.18); }
    else if(tipo==='warn'){ note(392,0,.15,.16); note(329.63,.14,.15,.16); }
    else                  { note(277.18,0,.38,.14); note(261.63,0,.38,.14); }
    setTimeout(()=>{ try{ctx.close();}catch(_){} },800);
  } catch(e){ /* sin audio */ }
}

/* ══════════════════════════════════════════════
   MÓDULO 12: SESIÓN PERSISTENTE
   No cierra por suspensión de laptop.
   Solo cierra con botón explícito.
   ══════════════════════════════════════════════ */
function actualizarHoraEntrada(val) {
  EC.horaEntrada = val;
  // Sincronizar ambos inputs de hora
  const he  = document.getElementById('horaEntrada');       if(he)  he.value=val;
  const hec = document.getElementById('horaEntradaConfig'); if(hec) hec.value=val;
  actualizarStatusBar();
  
  audit('Hora límite actualizada: ' + val, 'INFO');
}

function esTardio(hora) {
  if(!hora || !EC.horaEntrada) return false;
  const [hE,mE] = EC.horaEntrada.split(':').map(Number);
  const [hS,mS] = hora.split(':').map(Number);
  return (hS > hE) || (hS===hE && mS > mE);
}

function actualizarBannerJornada() {
  const banner = document.getElementById('jornadaBanner'); if(!banner) return;
  const lbl    = document.getElementById('jbLabel');
  const ico    = document.getElementById('jbIco');
  const dot    = document.getElementById('sdDot');
  const sbJ    = document.getElementById('sbJornada');
  const map = {
    idle:     {cls:'jb-idle',txt:'Sin iniciar',     ic:'⚪', dot:''},
    activa:   {cls:'jb-act', txt:'Jornada activa',  ic:'🟢', dot:'sd-activa'},
    cerrada:  {cls:'jb-cerr',txt:'Jornada cerrada — reapertura disponible', ic:'🟠', dot:'sd-cerrada'},
    reabierta:{cls:'jb-reab',txt:'Jornada reabierta — registrando tardíos', ic:'🟡', dot:'sd-activa'},
  };
  const {cls,txt,ic,dot:dc} = map[EC.jornadaEstado]||map.idle;
  banner.className = 'jb ' + cls;
  if(lbl) lbl.textContent = txt;
  if(ico) ico.textContent = ic;
  if(dot) { dot.className='status-dot'; if(dc) dot.classList.add(dc); }
  if(sbJ) sbJ.textContent = txt;
}

function toggleModo() {
  EC.modoSalida = document.getElementById('chkSalida')?.checked || false;
  const b = document.getElementById('modoBadge');
  if(b) {
    b.textContent = EC.modoSalida ? '⬇️ MODO SALIDA' : '⬆️ MODO ENTRADA';
    b.className   = EC.modoSalida ? 'badge b-nj' : 'badge b-vd';
  }
  audit('Modo escáner: ' + (EC.modoSalida?'SALIDA':'ENTRADA'), 'INFO');
}

async function iniciarSesion() {
  const nameEl = document.getElementById('profName');
  const name = nameEl?.value.trim();
  if(!name){ toast('⚠️ Ingresa el nombre del docente','warn'); return; }
  EC.profName = sanitize(name);
  desbloquearAudio(); // desbloqueo en click real del usuario

  document.getElementById('loginBox')?.classList.add('hidden');
  document.getElementById('scannerBox')?.classList.remove('hidden');
  const pi = document.getElementById('profInfo');
  if(pi) pi.textContent = `Prof. ${desanitize(EC.profName)}`;

  if(!EC.alumnos.length) {
    const al = document.getElementById('alertSinLista'); if(al) al.style.display='flex';
  }

  // Intentar restaurar sesión del mismo día
  const sesion = await cargarSesion();
  const hoy    = new Date().toDateString();
  if(sesion && sesion.fecha===hoy && sesion.regs?.length>0) {
    const mm = document.getElementById('mRestoreMsg');
    if(mm) mm.innerHTML = `Sesión del <strong style="color:#fff;">${sesion.fecha}</strong> con <strong style="color:#fff;">${sesion.regs.length} registros</strong>.<br><br>Docente: ${sanitize(sesion.prof||'—')}<br><br>¿Restaurar para no repetir carnets ya escaneados?`;
    const mr = document.getElementById('mRestore'); if(mr) mr.classList.remove('hidden');
    window._sesionPendiente = sesion;
    return;
  }

  EC.jornadaEstado = 'activa';
  actualizarBannerJornada();
  iniciarScanner();
  actualizarStatusBar();
  renderListas(); renderTablaGlobal(); renderDashboard();
  audit(`Sesión iniciada: ${EC.profName}`, 'OK');
  toast(`🚀 Bienvenido/a, ${desanitize(EC.profName)}`, 'ok');
}

async function restaurarSesion() {
  const s = window._sesionPendiente;
  cerrarModal('mRestore');
  if(!s) { EC.jornadaEstado='activa'; actualizarBannerJornada(); iniciarScanner(); return; }

  // Restaurar lista de alumnos si no está cargada (p.ej. al reabrir el navegador)
  if(!EC.alumnos.length && s.alumnos?.length) {
    EC.alumnos = s.alumnos;
    guardarLista();
    toast('📋 Lista de alumnos recuperada desde sesión guardada', 'info', 4000);
  }

  // Restaurar registros — funciona aunque EC.alumnos esté vacío usando los nombres
  // guardados en cada reg (campos ap/nm). Retrocompatible con el formato anterior.
  EC.registros = [];
  if(s.regs?.length) {
    const fechaFallback = new Date().toLocaleDateString('es-VE',{timeZone:'America/Caracas'});
    s.regs.forEach(r => {
      const a = EC.alumnos.find(x=>x.id===r.i);
      if(a) {
        EC.registros.push({...a, hora:r.h, tipo:r.t, tardio:r.tar||false, fecha:r.f||fechaFallback});
      } else if(r.ap) {
        // Fallback: datos de nombre guardados dentro del propio registro
        EC.registros.push({id:r.i, nro:r.nr||0, apellido:r.ap, nombre:r.nm||'', grado:'?', seccion:'?', hora:r.h, tipo:r.t, tardio:r.tar||false, fecha:r.f||fechaFallback});
      }
    });
  }
  if(s.retardos) Object.assign(EC.histRetardos, s.retardos);
  EC.jornadaEstado = s.estado || 'activa';
  EC.horaEntrada   = s.hora   || '07:15';
  actualizarHoraEntrada(EC.horaEntrada);
  actualizarBannerJornada();
  iniciarScanner();
  actualizarTodo();
  guardarSesion(); // actualiza localStorage al nuevo formato con ap/nm/alumnos
  toast(`✅ Sesión restaurada · ${EC.registros.length} registros recuperados`, 'ok', 5000);
  audit(`Sesión restaurada: ${EC.registros.length} registros`, 'OK');
  window._sesionPendiente = null;
}

async function descartarSesion() {
  cerrarModal('mRestore');
  Store.removeItem(LS_KEY);
  EC.registros = []; EC.jornadaEstado = 'activa';
  actualizarBannerJornada();
  iniciarScanner();
  actualizarTodo();
  audit('Sesión anterior descartada — nuevo día iniciado', 'WARN');
  window._sesionPendiente = null;
}

async function confirmarCierreSesion() {
  const regsE = EC.registros.filter(r=>r.tipo==='ENTRADA');
  const tard  = regsE.filter(r=>r.tardio).length;
  const ok    = confirm(
    `📊 RESUMEN DE CIERRE\n\nHoy asistieron ${regsE.length} de ${EC.alumnos.length} alumnos.\nSe detectaron ${tard} retardo(s).\n\n¿Exportar el Excel y cerrar la sesión?`
  );
  if(!ok) return;
  await exportarExcelFinal();
  EC.registros=[]; EC.jornadaEstado='idle'; EC.profName='';
  Store.removeItem(LS_KEY);
  detenerScanner();
  document.getElementById('loginBox')?.classList.remove('hidden');
  document.getElementById('scannerBox')?.classList.add('hidden');
  const pn=document.getElementById('profName'); if(pn) pn.value='';
  actualizarBannerJornada(); actualizarTodo();
  toast('✅ Sesión cerrada. Sistema en espera para el próximo día.','ok',6000);
  audit('Sesión cerrada definitivamente','INFO');
}

