/* ══════════════════════════════════════════════
   MÓDULO 13: ESCÁNER QR
   NotAllowedError → instrucción permisos clara
   NotFoundError   → activa ingreso manual
   ══════════════════════════════════════════════ */
function iniciarScanner() {
  if(EC.scanActivo) return;
  EC.qr5 = new Html5Qrcode('reader');
  EC.qr5.start(
    {facingMode:'environment'},
    {fps:12, qrbox:{width:190,height:190}},
    onScanOK, ()=>{}
  ).then(()=>{
    EC.scanActivo = true;
    const ce=document.getElementById('camaraError'); if(ce) ce.classList.add('hidden');
    audit('Cámara iniciada correctamente','OK');
  }).catch(err=>{
    const s=String(err);
    const el=document.getElementById('camaraError');
    if(el){
      el.classList.remove('hidden');
      if(s.includes('NotAllowed')||s.includes('Permission')||s.includes('denied'))
        el.textContent='🔒 Permisos de cámara denegados. Ve a Configuración del navegador → Privacidad → Cámara → Permitir este sitio. Mientras tanto, usa el ingreso manual de ID arriba.';
      else if(s.includes('NotFound')||s.includes('device not found')||s.includes('Requested'))
        el.textContent='📷 Cámara no encontrada en este equipo. Usa el campo de ingreso manual de ID para registrar asistencia.';
      else
        el.textContent='⚠️ Error de cámara: '+s.slice(0,80)+'. Usa el ingreso manual.';
    }
    const sr=document.getElementById('scanResult');
    if(sr) sr.innerHTML='<div class="alert al-info">⌨️ Usa el ingreso manual para registrar asistencia</div>';
    audit('Error cámara: '+s.slice(0,60),'WARN');
  });
}

function detenerScanner() {
  if(EC.qr5 && EC.scanActivo) EC.qr5.stop().then(()=>{EC.scanActivo=false;}).catch(()=>{});
}

function escaneoManual() {
  const el = document.getElementById('inputManual');
  const id = (el?.value||'').trim();
  if(!id){ toast('⚠️ Ingresa un ID de carnet','warn'); return; }
  el.value = '';
  onScanOK(id);
}

/* ══════════════════════════════════════════════
   MÓDULO 14: CORE DEL ESCANEO — Transacción
   Detecta PUNTUAL vs TARDÍO por hora configurada.
   Reapertura dinámica si jornada estaba cerrada.
   Fila parpadeante sube al top 3 segundos.
   ══════════════════════════════════════════════ */
async function onScanOK(decoded) {
  if(EC.cooldown) return;
  EC.cooldown = true;
  setTimeout(()=>{ EC.cooldown=false; }, 2000);

  const alumno = EC.alumnos.find(a=>a.id===decoded);
  const hora   = new Date().toLocaleTimeString('es-VE',{hour:'2-digit',minute:'2-digit',second:'2-digit',timeZone:'America/Caracas'});
  const fechaStr = new Date().toLocaleDateString('es-VE',{timeZone:'America/Caracas'});
  const resDiv = document.getElementById('scanResult');

  if(!alumno) {
    if(resDiv) resDiv.innerHTML=`<div class="scan-result sr-err"><div class="sr-ico">❌</div><div class="sr-name">Código no reconocido</div><div class="sr-id">${sanitize(decoded.slice(0,24))}</div></div>`;
    playTono('err'); audit('QR no reconocido: '+decoded.slice(0,18),'WARN');
    setTimeout(()=>{ if(resDiv) resDiv.innerHTML='<div class="alert al-info">📷 Listo para escanear</div>'; }, 3500);
    return;
  }

  // Modo Salida
  if(EC.modoSalida) {
    const tieneEntrada = EC.registros.find(r=>r.id===decoded&&r.tipo==='ENTRADA');
    if(!tieneEntrada) {
      if(resDiv) resDiv.innerHTML=`<div class="scan-result sr-warn"><div class="sr-ico">⚠️</div><div class="sr-name">${alumno.apellido}, ${alumno.nombre}</div><div class="sr-id">Sin entrada registrada hoy</div></div>`;
      playTono('warn'); return;
    }
    document.getElementById('mSalidaInfo').innerHTML=`<strong style="color:#fff;">${alumno.apellido}, ${alumno.nombre}</strong><br><code class="mono">${alumno.id}</code>`;
    EC._salidaAlumno = alumno;
    cerrarModal_noExist(); // open salida modal
    const ms=document.getElementById('mSalida'); if(ms) ms.classList.remove('hidden');
    return;
  }

  // Verificar duplicado
  const yaPresente = EC.registros.find(r=>r.id===decoded&&r.tipo==='ENTRADA');
  if(yaPresente) {
    if(resDiv) resDiv.innerHTML=`<div class="scan-result sr-warn"><div class="sr-ico">⚠️</div><div class="sr-name">${alumno.apellido}, ${alumno.nombre}</div><div class="sr-id">Ya registrado hoy</div></div>`;
    playTono('warn'); return;
  }

  // Detectar tardío automáticamente
  const tardio = esTardio(hora);

  // Reapertura dinámica si jornada estaba cerrada
  if(EC.jornadaEstado==='cerrada') {
    EC.jornadaEstado='reabierta';
    actualizarBannerJornada();
    toast('🟡 Jornada reabierta — registrando llegada tardía','warn',4000);
    audit('Jornada reabierta automáticamente para llegada tardía','WARN');
  }

  // ── TRANSACCIÓN DE REGISTRO ──
  const reg = {...alumno, hora, fechaStr, tipo:'ENTRADA', tardio};
  EC.registros.push(reg);

  // Actualizar historial de retardos semanales
  if(tardio) {
    EC.histRetardos[alumno.id] = (EC.histRetardos[alumno.id]||0) + 1;
    if(EC.histRetardos[alumno.id]>=3) {
      toast(`⚖️ ${alumno.apellido} tiene ${EC.histRetardos[alumno.id]} retardos esta semana — LOE Art.56`,'warn',7000);
      audit(`AVISO LEGAL: ${alumno.apellido} ${alumno.nombre} — ${EC.histRetardos[alumno.id]} retardos`,'WARN');
    }
  }

  // Feedback visual diferenciado
  if(resDiv) {
    const clase = tardio ? 'sr-tard' : 'sr-ok';
    const ico   = tardio ? '🟠' : '✅';
    const label = tardio ? 'LLEGADA TARDÍA' : 'Entrada: ' + hora;
    resDiv.innerHTML=`<div class="scan-result ${clase}"><div class="sr-ico">${ico}</div><div class="sr-name">${alumno.apellido}, ${alumno.nombre}</div><div class="sr-id">${alumno.id}</div><div class="sr-hora">${label}</div></div>`;
  }
  playTono(tardio?'tard':'ok');

  // Pulso en icono ojo
  const ico=document.getElementById('icoEye');
  if(ico){ ico.classList.add('scan-pulse'); setTimeout(()=>ico.classList.remove('scan-pulse'),1400); }

  // Yield antes de actualizar UI (no bloquea escáner)
  await Promise.resolve();
  renderListas();
  agregarFilaTop(reg);   // Fila sube al top con parpadeo 3s
  actualizarContadores();
  renderDashboard();
  await guardarSesion(); // Solo ID+hora en localStorage

  audit(`${tardio?'TARDÍO':'ENTRADA'}: ${alumno.apellido} ${alumno.nombre} [${alumno.id}] ${hora}`, tardio?'WARN':'OK');
}

/* Protocolo de salida */
let _salidaAlumno = null;
function cancelarSalida() { cerrarModal('mSalida'); _salidaAlumno=null; }
function confirmarSalida() {
  const mot=document.getElementById('sMot')?.value;
  const ced=document.getElementById('sCed')?.value.trim();
  const nom=document.getElementById('sNom')?.value.trim();
  if(!mot||!ced||!nom){ toast('⚠️ Completa todos los campos','warn'); return; }
  const a=EC._salidaAlumno||_salidaAlumno;
  if(!a) return;
  const hora=new Date().toLocaleTimeString('es-VE',{hour:'2-digit',minute:'2-digit',second:'2-digit',timeZone:'America/Caracas'});
  EC.registros.push({...a, hora, fechaStr:new Date().toLocaleDateString('es-VE',{timeZone:'America/Caracas'}), tipo:'SALIDA', mot:sanitize(mot), ced:sanitize(ced), quien:sanitize(nom)});
  cerrarModal('mSalida');
  ['sMot','sCed','sNom'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
  EC._salidaAlumno=null; _salidaAlumno=null;
  guardarSesion(); playTono('warn');
  audit(`SALIDA: ${a.apellido} ${a.nombre} · ${mot} · ${sanitize(nom)} (${sanitize(ced)})`,'WARN');
  toast(`🚪 Salida registrada: ${a.apellido}`,'info');
}

function cerrarModal_noExist(){} // placeholder sin uso real

/* ══════════════════════════════════════════════
   MÓDULO 15: FILA PARPADEANTE — sube al top 3s
   ══════════════════════════════════════════════ */
function agregarFilaTop(reg) {
  const tbody=document.getElementById('tablaGlobal'); if(!tbody) return;
  const ret=EC.histRetardos[reg.id]||0;
  const tr=document.createElement('tr');
  tr.className='row-flash' + (reg.tardio?' row-tardio':'');
  tr.innerHTML=`
    <td>${reg.nro}</td>
    <td><div class="dato-priv" onclick="this.classList.toggle('rev')"><span class="dr">${sanitize(reg.apellido)}</span><span class="dm">👁</span></div></td>
    <td>${sanitize(reg.nombre)}</td>
    <td><code class="mono">${reg.id}</code></td>
    <td><span class="badge b-az">${reg.grado}°${reg.seccion}</span></td>
    <td>${reg.tardio?'<span class="badge b-nj">🟠 TARDÍO</span>':'<span class="badge b-vd">✅ PRESENTE</span>'}</td>
    <td><span class="badge ${ret>=3?'b-rj':ret>=1?'b-am':'b-gy'}">${ret}${ret>=3?' ⚖️':''}</span></td>
    <td><button class="btn btn-ghost btn-xs" onclick="verDetalleAlumno('${reg.id}')">👁</button></td>`;
  tbody.insertBefore(tr, tbody.firstChild);
  setTimeout(()=>tr.classList.remove('row-flash'), 3000);
}

/* ══════════════════════════════════════════════
   MÓDULO 16: LISTAS DINÁMICAS Pendientes / Presentes
   ══════════════════════════════════════════════ */
function renderListas() {
  const presIds = new Set(EC.registros.filter(r=>r.tipo==='ENTRADA').map(r=>r.id));
  const pend    = EC.alumnos.filter(a=>!presIds.has(a.id));
  const pres    = EC.registros.filter(r=>r.tipo==='ENTRADA').slice().reverse();

  const lp=document.getElementById('listaPend');
  if(lp) lp.innerHTML=pend.map(a=>`
    <div class="li-item">
      <span style="font-size:10px;color:var(--t3);min-width:22px;font-family:var(--mono);">${String(a.nro).padStart(2,'0')}</span>
      <span style="flex:1;font-size:11px;">${sanitize(a.apellido)}, ${sanitize(a.nombre)}</span>
    </div>`).join('');
  document.getElementById('badgePend')?.setAttribute('',pend.length)||
    (document.getElementById('badgePend')&&(document.getElementById('badgePend').textContent=pend.length));

  const lpres=document.getElementById('listaPres');
  if(lpres) lpres.innerHTML=pres.map(r=>`
    <div class="li-item ${r.tardio?'tard':'pres'}">
      <span style="font-size:10px;color:var(--t3);min-width:22px;font-family:var(--mono);">${String(r.nro).padStart(2,'0')}</span>
      <span style="flex:1;font-size:11px;">${sanitize(r.apellido)}, ${sanitize(r.nombre)}</span>
      <span style="font-size:10px;color:var(--t3);font-family:var(--mono);">${r.hora}${r.tardio?' 🟠':''}</span>
    </div>`).join('');
  const bp=document.getElementById('badgePend');  if(bp)  bp.textContent=pend.length;
  const bpr=document.getElementById('badgePres'); if(bpr) bpr.textContent=pres.length;
}

/* ══════════════════════════════════════════════
   MÓDULO 17: TABLA GLOBAL + TARJETAS IPA
   RETARDO automático por hora · Blur privacidad
   ══════════════════════════════════════════════ */
let _vistaCards = true;
function toggleVista() {
  _vistaCards = !_vistaCards;
  document.getElementById('vistaCards')?.classList.toggle('hidden', !_vistaCards);
  document.getElementById('vistaTabla')?.classList.toggle('hidden',  _vistaCards);
  const btn=document.getElementById('btnVista');
  if(btn) btn.textContent = _vistaCards ? '☰ Tabla' : '⊞ Tarjetas';
}

function renderTablaGlobal() {
  const empty=document.getElementById('emptyState');
  const tbody=document.getElementById('tablaGlobal');
  const cards=document.getElementById('vistaCards');
  if(!EC.alumnos.length) {
    if(empty) empty.style.display='block';
    if(tbody) tbody.innerHTML='';
    if(cards) cards.innerHTML='';
    return;
  }
  if(empty) empty.style.display='none';
  const q=(document.getElementById('buscador')?.value||'').toLowerCase();
  const lista=q ? EC.alumnos.filter(a=>fuzzyMatch(a.apellido+' '+a.nombre,q)) : EC.alumnos;

  // Vista tabla
  if(tbody) tbody.innerHTML=lista.map(a=>{
    const reg = EC.registros.find(r=>r.id===a.id&&r.tipo==='ENTRADA');
    // RETARDO automático: hora posterior a horaEntrada → RETARDO
    const tardio=reg?.tardio||false;
    const ret=EC.histRetardos[a.id]||0;
    const estado=reg ? (tardio?'<span class="badge b-nj">🟠 RETARDO</span>':'<span class="badge b-vd">✅ PRESENTE</span>') : '<span class="badge b-rj">✗ AUSENTE</span>';
    return `<tr${tardio?' class="row-tardio"':''}>
      <td>${a.nro}</td>
      <td><div class="dato-priv" onclick="this.classList.toggle('rev')"><span class="dr">${sanitize(a.apellido)}</span><span class="dm">👁</span></div></td>
      <td>${sanitize(a.nombre)}</td>
      <td><code class="mono">${a.id}</code></td>
      <td><span class="badge b-az">${a.grado}°${a.seccion}</span></td>
      <td>${estado}</td>
      <td><span class="badge ${ret>=3?'b-rj':ret>=1?'b-am':'b-gy'}">${ret}${ret>=3?' ⚖️':''}</span></td>
      <td>
        ${ret>=3?`<button class="btn btn-dngr btn-xs" onclick="abrirCitacion('${a.id}')">📋 Citar</button>`:''}
        ${!reg?`<button class="btn btn-prim btn-xs" onclick="registrarManual('${a.id}')">✅ Marcar</button>`:''}
        <button class="btn btn-ghost btn-xs" onclick="verDetalleAlumno('${a.id}')">👁</button>
      </td>
    </tr>`;
  }).join('');

  // Vista tarjetas
  if(cards) cards.innerHTML=lista.map(a=>{
    const reg = EC.registros.find(r=>r.id===a.id&&r.tipo==='ENTRADA');
    const tardio=reg?.tardio||false;
    const ret=EC.histRetardos[a.id]||0;
    const cls=reg?(tardio?'ipa-warn':'ipa-pres'):(ret>=3?'ipa-rj':'ipa-ok');
    const bc=reg?(tardio?'#fb923c':'#4ade80'):'#f87171';
    return `<div class="ipa-card ${cls}" onclick="verDetalleAlumno('${a.id}')">
      <div class="ipa-name dato-priv" onclick="event.stopPropagation();this.classList.toggle('rev')">
        <span class="dr">${sanitize(a.apellido)}</span><span class="dm">👁</span>
      </div>
      <div class="ipa-sub">${sanitize(a.nombre)} · ${a.grado}°${a.seccion}</div>
      <div class="ipa-bar-bg"><div class="ipa-bar" style="width:${reg?100:0}%;background:${bc};"></div></div>
      <div class="ipa-foot">
        <span style="font-weight:700;color:${bc};font-size:10px;">${reg?(tardio?'🟠 TARDÍO':'✅ PRESENTE'):'✗ AUSENTE'}</span>
        <span style="color:var(--t3);font-size:10px;">${reg?reg.hora:''}</span>
        ${ret>=3?`<span class="badge b-rj" style="font-size:8px;">⚖️ ${ret}</span>`:''}
      </div>
    </div>`;
  }).join('');

  // Subtítulo
  const rs=document.getElementById('regSubtitle');
  if(rs&&EC.alumnos.length) rs.textContent=`${EC.alumnos[0].grado}° Grado · Sección ${EC.alumnos[0].seccion} · ${EC.alumnos.length} alumnos · Hover = revelar apellido`;
}

function verDetalleAlumno(id) {
  const a=EC.alumnos.find(x=>x.id===id); if(!a) return;
  const reg=EC.registros.find(r=>r.id===id&&r.tipo==='ENTRADA');
  const ret=EC.histRetardos[id]||0;
  toast(`${desanitize(a.apellido)}, ${desanitize(a.nombre)} — ${reg?'Presente':'Ausente'} — Retardos sem.: ${ret}`, 'info', 5000);
}

function registrarManual(id) {
  // Registrar manualmente sin QR (para casos de carnet dañado)
  onScanOK(id);
}

/* ══════════════════════════════════════════════
   MÓDULO 18: CONTADORES EN TIEMPO REAL
   ══════════════════════════════════════════════ */
function actualizarContadores() {
  const total = EC.alumnos.length;
  const regsE = EC.registros.filter(r=>r.tipo==='ENTRADA');
  const pres  = regsE.length;
  const tard  = regsE.filter(r=>r.tardio).length;
  const aus   = Math.max(0, total-pres);
  const porc  = total>0 ? Math.round((pres/total)*100) : 0;

  const set=(id,v)=>{ const e=document.getElementById(id); if(e)e.textContent=v; };
  // Lector page stats
  set('cTotal',  total);
  set('cPres',   pres);
  set('cTard',   tard);
  set('cAus',    aus);
  set('cPorc',   porc+'%');
  // Registro page stats
  set('rTotal',  total);
  set('rPres',   pres);
  set('rTard',   tard);
  set('rAus',    aus);

  // Badge navbar
  const nb=document.getElementById('nbPres');
  if(nb){ if(pres>0){nb.textContent=pres;nb.classList.add('on');}else nb.classList.remove('on'); }
}

function actualizarTodo() {
  actualizarContadores();
  renderListas();
  renderTablaGlobal();
  renderDashboard();
  actualizarStatusBar();
}

/* ══════════════════════════════════════════════
   MÓDULO 19: FINALIZAR JORNADA
   Motor de Recalculado: Presentes vs Faltantes
   ══════════════════════════════════════════════ */
function abrirFinJornada() {
  if(!EC.alumnos.length){ toast('⚠️ Carga la lista primero','warn'); return; }
  const regsE   = EC.registros.filter(r=>r.tipo==='ENTRADA');
  const presIds = new Set(regsE.map(r=>r.id));
  const falt    = EC.alumnos.filter(a=>!presIds.has(a.id));
  const tard    = regsE.filter(r=>r.tardio).length;
  const porc    = EC.alumnos.length>0 ? Math.round((regsE.length/EC.alumnos.length)*100) : 0;

  // Fecha completa en español
  const fechaLarga = new Date().toLocaleDateString('es-VE',{weekday:'long',year:'numeric',month:'long',day:'numeric',timeZone:'America/Caracas'});
  const fd=document.getElementById('finFecha');
  if(fd) fd.textContent=`${fechaLarga} · Docente: ${desanitize(EC.profName)}`;

  const fr=document.getElementById('finResumen');
  if(fr) fr.innerHTML=`
    <div class="resumen-item"><div class="resumen-num" style="color:var(--vd);">${regsE.length}</div><div class="resumen-lbl">Presentes</div></div>
    <div class="resumen-item"><div class="resumen-num" style="color:var(--am);">${tard}</div><div class="resumen-lbl">Con Retardo</div></div>
    <div class="resumen-item"><div class="resumen-num" style="color:var(--rj);">${falt.length}</div><div class="resumen-lbl">Faltantes</div></div>`;

  const ff=document.getElementById('finFaltantes');
  if(ff) ff.innerHTML = falt.length
    ? falt.map(a=>`<div style="padding:5px 8px;background:rgba(220,38,38,.06);border-radius:7px;font-size:12px;margin-bottom:4px;display:flex;gap:8px;align-items:center;">
        <code class="mono">${a.id}</code><strong>${sanitize(a.apellido)}</strong>, ${sanitize(a.nombre)}
        <button class="btn btn-prim btn-xs" style="margin-left:auto;" onclick="registrarManual('${a.id}')">✅ Registrar</button>
      </div>`).join('')
    : '<div class="alert al-ok">✅ ¡Todos los alumnos asistieron hoy!</div>';

  const m=document.getElementById('mFinJornada'); if(m) m.classList.remove('hidden');
}

async function finalizarYExportar() {
  await exportarExcelFinal();
  EC.jornadaEstado='cerrada';
  actualizarBannerJornada();
  cerrarModal('mFinJornada');
  toast('✅ Excel exportado · Jornada cerrada · Reapertura disponible al escanear','ok',6000);
  audit('Jornada finalizada y Excel exportado','OK');
  await guardarSesion();
}

/* ══════════════════════════════════════════════
   MÓDULO 20: EXPORTACIONES EXCEL
   Columna Estado = PRESENTE / RETARDO / AUSENTE
   Automático por hora, sin trabajo manual extra.
   ══════════════════════════════════════════════ */
async function exportarExcelFinal() {
  if(!EC.alumnos.length){ toast('⚠️ Sin lista de alumnos','warn'); return; }
  const g=EC.alumnos[0]?.grado||'X', s=EC.alumnos[0]?.seccion||'X';
  const fecha    = new Date().toISOString().slice(0,10);
  const fechaVE  = new Date().toLocaleDateString('es-VE',{timeZone:'America/Caracas'});
  const regsE    = EC.registros.filter(r=>r.tipo==='ENTRADA');
  const pres=regsE.length, tard=regsE.filter(r=>r.tardio).length;

  const filas=[
    {'Campo':'Sistema El Carmen v5 — Reporte de Jornada Escolar', '':'',' ':'','  ':'','   ':'','    ':'','     ':'','      ':'','       ':''},
    {'Campo':`Docente: ${desanitize(EC.profName)} · Fecha: ${fechaVE} · Hora de entrada: ${EC.horaEntrada} · Matrícula: ${EC.alumnos.length} · Presentes: ${pres} · Tardíos: ${tard}`},
    {},
    ...EC.alumnos.map(a=>{
      const reg=regsE.find(r=>r.id===a.id);
      // Columna Estado inteligente: RETARDO automático por hora
      const estado = reg ? (reg.tardio ? 'RETARDO' : 'PRESENTE') : 'AUSENTE';
      const ret=EC.histRetardos[a.id]||0;
      return {
        'Nro':a.nro, 'Apellidos':desanitize(a.apellido), 'Nombres':desanitize(a.nombre),
        'ID Carnet':a.id, 'Grado':a.grado+'°', 'Sección':a.seccion,
        'Estado':estado, 'Hora Entrada':reg?reg.hora:'',
        'Retardos Semana':ret, 'Requiere Citación':ret>=3?'SÍ':'NO',
        'Fecha':fechaVE, 'Docente':desanitize(EC.profName),
        'Firma Digital':btoa(a.id+fecha+estado+EC.profName),
      };
    }),
    {},
    {'Campo':`FIRMA GLOBAL: ${btoa(EC.profName+fecha+EC.alumnos.length+EC.registros.length)}`},
  ];
  const ws=XLSX.utils.json_to_sheet(filas);
  const wb=XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb,ws,'Jornada');
  XLSX.writeFile(wb,`Jornada_${g}${s}_${fecha}.xlsx`);
  audit(`Excel final exportado: ${EC.alumnos.length} alumnos, ${pres} presentes`,'OK');
}

async function exportSesion() {
  await exportarExcelFinal();
  toast('📥 Excel exportado','ok');
}

async function exportGlobal() {
  // Reporte SEP: incluye todos los alumnos con estado del día
  if(!EC.alumnos.length){ toast('⚠️ Sin lista','warn'); return; }
  const g=EC.alumnos[0]?.grado||'X', s=EC.alumnos[0]?.seccion||'X';
  const fecha   = new Date().toISOString().slice(0,10);
  const fechaVE = new Date().toLocaleDateString('es-VE',{timeZone:'America/Caracas'});

  const filas=[
    {'Campo':'Reporte SEP — Sistema El Carmen v5', '':'',' ':'','  ':''},
    {'Campo':`${fechaVE} · ${EC.alumnos[0]?.grado}° Grado · Sección ${EC.alumnos[0]?.seccion} · Docente: ${desanitize(EC.profName)}`},
    {},
    ...EC.alumnos.map(a=>{
      const reg=EC.registros.find(r=>r.id===a.id&&r.tipo==='ENTRADA');
      const tardio=reg?.tardio||false;
      const ret=EC.histRetardos[a.id]||0;
      return {
        'Nro':a.nro,'Apellidos':desanitize(a.apellido),'Nombres':desanitize(a.nombre),
        'ID':a.id,'Grado':a.grado+'°','Sección':a.seccion,
        'Estado Hoy':reg?(tardio?'RETARDO':'PRESENTE'):'AUSENTE',
        'Hora':reg?reg.hora:'','Retardos Semana':ret,
        'Citación Requerida':ret>=3?'SÍ':'NO',
        'Fecha':fechaVE,'Docente':desanitize(EC.profName),
      };
    }),
  ];
  const ws=XLSX.utils.json_to_sheet(filas);
  const wb=XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb,ws,'Reporte SEP');
  XLSX.writeFile(wb,`Reporte_SEP_${g}${s}_${fecha}.xlsx`);
  toast('📊 Reporte SEP exportado','ok');
  audit('Reporte SEP exportado','OK');
}

/* ══════════════════════════════════════════════
   MÓDULO 21: RECUENTO DE EMERGENCIA (FAB 🆘)
   Un clic en cualquier momento de la sesión.
   ══════════════════════════════════════════════ */
function recuentoEmergencia() {
  const pres=EC.registros.filter(r=>r.tipo==='ENTRADA');
  const ec=document.getElementById('emergContent'); if(!ec) return;
  ec.innerHTML=`
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:12px;text-align:center;">
      <div style="background:rgba(22,163,74,.1);border-radius:10px;padding:10px;"><div style="font-size:24px;font-weight:900;color:var(--vd);">${pres.length}</div><div class="t-sm">En aula</div></div>
      <div style="background:rgba(220,38,38,.1);border-radius:10px;padding:10px;"><div style="font-size:24px;font-weight:900;color:var(--rj);">${Math.max(0,EC.alumnos.length-pres.length)}</div><div class="t-sm">Ausentes</div></div>
      <div style="background:rgba(14,165,233,.1);border-radius:10px;padding:10px;"><div style="font-size:24px;font-weight:900;color:var(--az);">${EC.alumnos.length}</div><div class="t-sm">Matrícula</div></div>
    </div>
    <div style="font-size:11px;color:var(--t3);margin-bottom:8px;">📅 ${new Date().toLocaleString('es-VE',{timeZone:'America/Caracas'})} · Docente: ${desanitize(EC.profName)||'—'}</div>
    <div style="max-height:200px;overflow-y:auto;">
      ${pres.map((r,i)=>`<div style="padding:5px 9px;background:rgba(22,163,74,.07);border-radius:7px;font-size:12px;margin-bottom:3px;display:flex;gap:8px;align-items:center;">
        <span style="color:var(--vd);min-width:22px;font-family:var(--mono);">${i+1}</span>
        <strong>${sanitize(r.apellido)}</strong>, ${sanitize(r.nombre)}
        <span style="margin-left:auto;color:var(--t3);font-family:var(--mono);">${r.hora}${r.tardio?' 🟠':''}</span>
      </div>`).join('') || '<div class="alert al-warn">⚠️ Ningún alumno registrado aún</div>'}
    </div>`;
  const m=document.getElementById('mEmerg'); if(m) m.classList.remove('hidden');
  audit(`Recuento emergencia: ${pres.length} presentes`,'INFO');
}

function imprimirEmerg() {
  const pres=EC.registros.filter(r=>r.tipo==='ENTRADA');
  const fechaStr=new Date().toLocaleString('es-VE',{timeZone:'America/Caracas'});
  try {
    const {jsPDF}=window.jspdf;
    const doc=new jsPDF({orientation:'portrait',unit:'mm',format:'a4'});
    doc.setFillColor(220,38,38); doc.rect(0,0,210,20,'F');
    doc.setTextColor(255,255,255); doc.setFontSize(14); doc.setFont('helvetica','bold');
    doc.text('🆘 EMERGENCIA — ESCUELA EL CARMEN',10,12);
    doc.setFontSize(9); doc.setFont('helvetica','normal');
    doc.text(`Presentes: ${pres.length} de ${EC.alumnos.length} · Docente: ${desanitize(EC.profName)||'—'}`,10,22);
    doc.setTextColor(0,0,0); let y=32;
    ['#','Apellidos y Nombres','ID','Hora','✓'].forEach((h,i)=>{
      const xs=[10,22,115,148,183];
      doc.setFontSize(8); doc.setFont('helvetica','bold'); doc.text(h,xs[i],y);
    });
    doc.setLineWidth(0.3); doc.setDrawColor(14,165,233); doc.line(8,y+2,202,y+2);
    y+=8; doc.setFont('helvetica','normal');
    pres.forEach((r,i)=>{
      if(y>272){ doc.addPage(); y=15; }
      if(i%2===0){ doc.setFillColor(240,249,255); doc.rect(8,y-4,194,7,'F'); }
      doc.setFontSize(9);
      doc.text(String(i+1),10,y);
      doc.text(`${desanitize(r.apellido)}, ${desanitize(r.nombre)}`.slice(0,38),22,y);
      doc.text(r.id,115,y); doc.text('☐',184,y);
      y+=8;
    });
    doc.save(`EMERGENCIA_${new Date().toISOString().slice(0,10)}.pdf`);
  } catch(e) {
    const w=window.open('','_blank');
    w.document.write(`<html><body style="font-family:Arial;padding:15px;">
      <h2 style="background:#dc2626;color:#fff;padding:10px;border-radius:6px;">🆘 EMERGENCIA — EL CARMEN</h2>
      <p>${fechaStr} · Presentes: ${pres.length}/${EC.alumnos.length}</p>
      <table border="1" style="width:100%;border-collapse:collapse;font-size:11px;margin-top:10px;">
        <tr style="background:#f1f5f9;"><th>#</th><th>Alumno</th><th>ID</th><th>Hora</th><th>✓</th></tr>
        ${pres.map((r,i)=>`<tr><td>${i+1}</td><td>${desanitize(r.apellido)}, ${desanitize(r.nombre)}</td><td>${r.id}</td><td>${r.hora}</td><td>☐</td></tr>`).join('')}
      </table><script>window.onload=()=>window.print();<\/script></body></html>`);
  }
  cerrarModal('mEmerg');
  audit(`PDF emergencia: ${pres.length} alumnos`,'WARN');
}

function emergSismo() { recuentoEmergencia(); } // alias por compatibilidad

/* ══════════════════════════════════════════════
   MÓDULO 22: DASHBOARD DE RETARDOS
   Semáforo: 🟢1 · 🟡2 · 🔴3+ (aviso LOE)
   ══════════════════════════════════════════════ */
function renderDashboard() {
  const dr=document.getElementById('dashRetardos');
  const dp=document.getElementById('dashPuntuales');
  if(!dr) return;

  const conR = EC.alumnos.filter(a=>(EC.histRetardos[a.id]||0)>0)
    .sort((a,b)=>(EC.histRetardos[b.id]||0)-(EC.histRetardos[a.id]||0));
  const sinR = EC.alumnos.filter(a=>(EC.histRetardos[a.id]||0)===0);

  if(!conR.length) {
    dr.innerHTML='<div class="alert al-ok">✅ Ningún alumno con retardos registrados esta semana.</div>';
  } else {
    dr.innerHTML=conR.map(a=>{
      const c=EC.histRetardos[a.id]||0;
      const alerta=c>=3;
      const ico=c>=3?'🔴':c>=2?'🟡':'🟢';
      return `<div class="ret-card${alerta?' alerta':''}">
        <span style="font-size:22px;">${ico}</span>
        <div style="flex:1;">
          <div style="font-size:12px;font-weight:700;color:#fff;">${sanitize(a.apellido)}, ${sanitize(a.nombre)}</div>
          <div class="t-sm">${a.grado}° · Sec. ${a.seccion} · <strong style="color:${alerta?'#f87171':'#fbbf24'}">${c} retardo(s)</strong> esta semana</div>
          ${alerta?'<div style="font-size:10px;color:#f87171;margin-top:2px;">⚖️ LOE Art.56 — Notificar al representante obligatoriamente</div>':''}
        </div>
        <span class="badge ${c>=3?'b-rj':c>=2?'b-am':'b-vd'}">${c}</span>
        ${alerta?`<button class="btn btn-dngr btn-xs" onclick="abrirCitacion('${a.id}')">📋 Citar</button>`:''}
      </div>`;
    }).join('');
  }

  if(dp) dp.innerHTML = !sinR.length
    ? '<div class="t-sm" style="color:var(--t3);">Todos los alumnos tienen al menos un retardo registrado.</div>'
    : sinR.map(a=>`<span style="display:inline-flex;align-items:center;gap:6px;background:rgba(22,163,74,.1);border:1px solid rgba(22,163,74,.22);border-radius:9px;padding:6px 11px;margin:3px;font-size:11px;color:#4ade80;">
        ⭐ <strong>${sanitize(a.apellido)}</strong>, ${sanitize(a.nombre)}
      </span>`).join('');

  // Badge dashboard
  const nd=document.getElementById('nbDash');
  const enAlerta=conR.filter(a=>(EC.histRetardos[a.id]||0)>=3).length;
  if(nd){ if(enAlerta>0){nd.textContent=enAlerta;nd.classList.add('on');}else nd.classList.remove('on'); }
}

function limpiarCicloRetardos() {
  if(!confirm('🗓️ ¿Iniciar nuevo ciclo semanal?\n\nSe reiniciarán los contadores de retardos.\nLa lista de alumnos se conserva.')) return;
  EC.histRetardos={};
  EC.alumnos.forEach(a=>{ EC.histRetardos[a.id]=0; });
  renderDashboard(); actualizarContadores();
  guardarSesion();
  toast('✅ Ciclo semanal reiniciado','ok');
  audit('Ciclo semanal de retardos limpiado','WARN');
}

