/* ══════════════════════════════════════════════
   MÓDULO 24: GENERADOR DE QR + CARNETS
   ══════════════════════════════════════════════ */
function generateAllQRs() {
  if(!EC.alumnos.length){ toast('⚠️ Carga primero el Excel','warn'); return; }
  const grid=document.getElementById('qrGrid'); if(!grid) return;
  grid.innerHTML='';
  document.getElementById('qrSection')?.classList.remove('hidden');
  const qs=document.getElementById('qrSubtitle'); if(qs) qs.textContent=`Generando ${EC.alumnos.length} carnets...`;

  EC.alumnos.forEach((a,i)=>{
    const div=document.createElement('div');
    div.className='qr-card';
    const qd=document.createElement('div'); qd.id=`qr-${i}`; qd.style.cssText='width:108px;height:108px;margin:0 auto 7px;';
    const nm=document.createElement('div'); nm.style.cssText='font-size:11px;font-weight:700;color:#fff;'; nm.textContent=a.apellido;
    const nn=document.createElement('div'); nn.style.cssText='font-size:10px;color:var(--t2);'; nn.textContent=a.nombre;
    const ni=document.createElement('code'); ni.className='mono'; ni.style.display='block'; ni.style.margin='3px 0'; ni.textContent=a.id;
    const ng=document.createElement('div'); ng.style.cssText='font-size:10px;color:var(--t3);'; ng.textContent=`${a.grado}° · Sec. ${a.seccion}`;
    const btns=document.createElement('div'); btns.style.cssText='display:flex;gap:4px;margin-top:7px;';
    const bPr=document.createElement('button'); bPr.className='btn btn-ghost btn-xs'; bPr.style.flex='1'; bPr.textContent='🖨️'; bPr.dataset.act='print'; bPr.dataset.i=i;
    const bDl=document.createElement('button'); bDl.className='btn btn-nj    btn-xs'; bDl.style.flex='1'; bDl.textContent='⬇️'; bDl.dataset.act='png';   bDl.dataset.i=i;
    btns.append(bPr, bDl);
    div.append(qd, nm, nn, ni, ng, btns);
    grid.appendChild(div);
  });

  // Cola de microtareas — no bloquea el hilo principal
  let idx=0;
  const next=()=>{
    if(idx>=EC.alumnos.length){
      if(qs) qs.textContent=`${EC.alumnos.length} carnets listos ✅`;
      audit(`${EC.alumnos.length} QR generados`,'OK');
      return;
    }
    const cont=document.getElementById(`qr-${idx}`);
    if(cont&&EC.alumnos[idx].id)
      try{ new QRCode(cont,{text:EC.alumnos[idx].id,width:108,height:108,colorDark:'#0c4a6e',colorLight:'#fff',correctLevel:QRCode.CorrectLevel.M}); }
      catch(e){}
    idx++; setTimeout(next,22);
  };
  next();

  grid.onclick=e=>{
    const btn=e.target.closest('button[data-act]'); if(!btn) return;
    const i=parseInt(btn.dataset.i), a=EC.alumnos[i]; if(!a) return;
    btn.dataset.act==='print' ? imprimirCarnet(i,a) : descargarCarnetPNG(i,a);
  };
  grid.scrollIntoView({behavior:'smooth'});
}

