function imprimirCarnet(idx, a) {
  const canvas=document.querySelector(`#qr-${idx} canvas`);
  if(!canvas){ toast('⏳ QR aún generándose','warn'); return; }
  const w=window.open('','_blank'); if(!w){ toast('⚠️ Permite ventanas emergentes','warn'); return; }
  const b=w.document.body;
  w.document.write('<html><head><title>Carnet</title></head><body style="font-family:Arial;text-align:center;padding:16px;background:#fff;"></body></html>');
  w.document.close();
  const logo=w.document.createElement('img'); logo.src='data:image/jpeg;base64,'+LOGO; logo.style.cssText='width:54px;border-radius:50%;border:2px solid #0ea5e9;';
  const t1=w.document.createElement('h3'); t1.style.cssText='color:#0f172a;margin:6px 0 2px;font-size:14px;'; t1.textContent=`${desanitize(a.apellido)}, ${desanitize(a.nombre)}`;
  const t2=w.document.createElement('p');  t2.style.cssText='color:#64748b;font-size:10px;margin:0 0 8px;'; t2.textContent=`${a.grado}° · Sec. ${a.seccion}`;
  const qi=w.document.createElement('img'); qi.src=canvas.toDataURL(); qi.style.cssText='width:142px;height:142px;display:block;margin:0 auto;';
  const t3=w.document.createElement('p');  t3.style.cssText='font-family:monospace;color:#0ea5e9;font-size:11px;'; t3.textContent=a.id;
  const bar=w.document.createElement('div'); bar.style.cssText='background:#ea580c;height:8px;border-radius:4px;margin-top:13px;';
  const sc=w.document.createElement('script'); sc.textContent='window.onload=()=>window.print();';
  w.document.body.append(logo,t1,t2,qi,t3,bar,sc);
}

function descargarCarnetPNG(idx, a) {
  const canvas=document.querySelector(`#qr-${idx} canvas`);
  if(!canvas){ toast('⏳ QR aún generándose','warn'); return; }
  const off=document.createElement('canvas'); off.width=320; off.height=200;
  const ctx=off.getContext('2d');
  ctx.fillStyle='#fff'; ctx.fillRect(0,0,320,200);
  ctx.fillStyle='#0369a1'; ctx.fillRect(0,0,320,46);
  const img=new Image();
  img.onload=()=>{
    ctx.save(); ctx.beginPath(); ctx.arc(25,23,17,0,Math.PI*2); ctx.clip(); ctx.drawImage(img,8,6,34,34); ctx.restore();
    ctx.fillStyle='#fff'; ctx.font='bold 11px Arial'; ctx.fillText('ESCUELA EL CARMEN',52,16);
    ctx.font='9px Arial'; ctx.fillText(`${a.grado}° · Sec. ${a.seccion}`,52,30);
    ctx.fillStyle='#e0f2fe'; ctx.fillRect(0,46,200,154); ctx.fillStyle='#0ea5e9'; ctx.fillRect(0,46,4,154);
    ctx.drawImage(canvas,205,50,106,106);
    ctx.fillStyle='#0f172a'; ctx.font='bold 12px Arial'; ctx.fillText(desanitize(a.apellido).slice(0,19),10,74);
    ctx.font='10px Arial'; ctx.fillStyle='#334155'; ctx.fillText(desanitize(a.nombre).slice(0,22),10,90);
    ctx.fillStyle='#0ea5e9'; ctx.font='bold 9px monospace'; ctx.fillText(a.id,10,110);
    ctx.fillStyle='#ea580c'; ctx.fillRect(0,186,320,14);
    const lnk=document.createElement('a'); lnk.download=`carnet_${a.id}.png`; lnk.href=off.toDataURL('image/png'); lnk.click();
  };
  img.src='data:image/jpeg;base64,'+LOGO; // Logo Base64 — sin rutas externas
}

/* ══════════════════════════════════════════════
   MÓDULO 25: CARNETS PPTX con Logo Base64
   8 carnets por página · Membrete MPPE tricolor
   ══════════════════════════════════════════════ */
/* ══════════════════════════════════════════════
   HELPER: Genera QR como DataURL de forma interna
   sin necesidad de que el usuario haya visitado
   la pestaña Lista primero.
   ══════════════════════════════════════════════ */
function generarQRDataURL(texto, size=200) {
  return new Promise((resolve) => {
    const tmp = document.createElement('div');
    tmp.style.cssText = 'position:absolute;left:-9999px;top:-9999px;width:'+size+'px;height:'+size+'px;';
    document.body.appendChild(tmp);
    try {
      new QRCode(tmp, {
        text: texto, width: size, height: size,
        colorDark: '#0c4a6e', colorLight: '#ffffff',
        correctLevel: QRCode.CorrectLevel.M,
      });
      // QRCode.js crea el canvas de forma síncrona
      setTimeout(() => {
        const canvas = tmp.querySelector('canvas');
        const dataURL = canvas ? canvas.toDataURL('image/png') : null;
        document.body.removeChild(tmp);
        resolve(dataURL);
      }, 60);
    } catch(e) {
      try { document.body.removeChild(tmp); } catch(_) {}
      resolve(null);
    }
  });
}

async function generarCarnetsPPTX() {
  if(!EC.alumnos.length){ toast('⚠️ Carga primero el Excel','warn'); return; }
  if(typeof PptxGenJS==='undefined'){ toast('⚠️ PptxGenJS no disponible. Verifica la conexión a internet para cargar la librería.','err',7000); return; }
  if(typeof QRCode==='undefined'){ toast('⚠️ QRCode.js no disponible','err',5000); return; }
  const btn=document.getElementById('btnPPTX');
  if(btn){ btn.textContent='⏳ Generando...'; btn.disabled=true; }
  try {
    // Pre-generar todos los QR internamente (sin necesitar la pestaña Lista)
    toast('⏳ Generando QR internamente (' + EC.alumnos.length + ' carnets)...', 'info', 3000);
    const qrDataURLs = await Promise.all(
      EC.alumnos.map(a => generarQRDataURL(a.id, 180))
    );
    toast('✅ QR listos. Construyendo PPTX...', 'info', 2500);

    const pptx=new PptxGenJS();
    // Definir layout LETTER (8.5 × 11 pulgadas) — PptxGenJS no lo incluye por defecto
    pptx.defineLayout({name:'LETTER_PORTRAIT', width:8.5, height:11});
    pptx.layout = 'LETTER_PORTRAIT';
    pptx.title  = 'Carnets El Carmen v5';
    // Posiciones: 2 col × 4 fil = 8 carnets por hoja (8.5×11")
    const CX=[0.25,4.35], CY=[0.45,3.0,5.55,8.1], CW=3.8, CH=2.3;
    const totalPags=Math.ceil(EC.alumnos.length/8);
    for(let pg=0;pg<EC.alumnos.length;pg+=8){
      const slide=pptx.addSlide();
      // Membrete tricolor Venezuela
      slide.addShape(pptx.ShapeType.rect,{x:0,y:0,w:8.5,h:0.09,fill:{color:'CF142B'}});
      slide.addShape(pptx.ShapeType.rect,{x:0,y:0.09,w:8.5,h:0.09,fill:{color:'FFD700'}});
      slide.addShape(pptx.ShapeType.rect,{x:0,y:0.18,w:8.5,h:0.09,fill:{color:'003087'}});
      // Logo institucional Base64 — no depende de archivos externos
      try{ slide.addImage({data:'data:image/jpeg;base64,'+LOGO,x:0.3,y:0.32,w:0.38,h:0.38}); }catch(e){}
      slide.addText('REPÚBLICA BOLIVARIANA DE VENEZUELA — MPPE',{x:0.78,y:0.30,w:7.2,h:0.17,fontSize:7,bold:true,color:'003087',fontFace:'Arial'});
      slide.addText('SISTEMA NACIONAL DE IDENTIDAD ESTUDIANTIL',{x:0.78,y:0.45,w:7.2,h:0.14,fontSize:6,color:'64748B',fontFace:'Arial'});
      slide.addShape(pptx.ShapeType.line,{x:0.3,y:0.72,w:7.9,h:0,line:{color:'0EA5E9',width:0.8}});
      slide.addText(`Página ${Math.floor(pg/8)+1} de ${totalPags}  ·  Grado ${EC.alumnos[0]?.grado}° · Sección ${EC.alumnos[0]?.seccion}  ·  Docente: ${desanitize(EC.profName)||''}`,
        {x:0.3,y:0.73,w:7.9,h:0.15,fontSize:6,color:'94A3B8',fontFace:'Arial',align:'right'});
      EC.alumnos.slice(pg,pg+8).forEach((a,li)=>{
        const col=li%2, row=Math.floor(li/2), x=CX[col], y=CY[row];
        // Fondo tarjeta
        slide.addShape(pptx.ShapeType.roundRect,{x,y,w:CW,h:CH,fill:{color:'FFFFFF'},line:{color:'0EA5E9',width:1.2},rectRadius:0.07});
        // Header azul
        slide.addShape(pptx.ShapeType.rect,{x,y,w:CW,h:0.36,fill:{color:'0369A1'}});
        try{ slide.addImage({data:'data:image/jpeg;base64,'+LOGO,x:x+0.05,y:y+0.05,w:0.26,h:0.26}); }catch(e){}
        slide.addText('ESCUELA EL CARMEN',{x:x+0.36,y:y+0.06,w:3.0,h:0.14,fontSize:7,bold:true,color:'FFFFFF',fontFace:'Arial'});
        slide.addText(`${a.grado}° Grado · Sección ${a.seccion}`,{x:x+0.36,y:y+0.20,w:3.0,h:0.12,fontSize:5.5,color:'BAE6FD',fontFace:'Arial'});
        // Datos del alumno
        slide.addText(desanitize(a.apellido).slice(0,22),{x:x+0.1,y:y+0.44,w:2.2,h:0.20,fontSize:9,bold:true,color:'0F172A',fontFace:'Arial'});
        slide.addText(desanitize(a.nombre).slice(0,24),{x:x+0.1,y:y+0.63,w:2.2,h:0.18,fontSize:7.5,color:'334155',fontFace:'Arial'});
        slide.addText(a.id,{x:x+0.1,y:y+0.83,w:2.2,h:0.16,fontSize:7,color:'0EA5E9',fontFace:'Courier New',bold:true});
        slide.addText(`Nro: ${a.nro}`,{x:x+0.1,y:y+0.99,w:2.2,h:0.14,fontSize:6,color:'94A3B8',fontFace:'Arial'});
        // Divisor vertical
        slide.addShape(pptx.ShapeType.line,{x:x+2.33,y:y+0.40,w:0,h:CH-0.55,line:{color:'E2E8F0',width:0.5}});
        // QR (pre-generado internamente)
        const qrUrl = qrDataURLs[pg+li];
        if(qrUrl) try{ slide.addImage({data:qrUrl,x:x+2.36,y:y+0.40,w:1.14,h:1.14}); }catch(e){}
        // Footer naranja
        slide.addShape(pptx.ShapeType.rect,{x,y:y+CH-0.14,w:CW,h:0.14,fill:{color:'EA580C'}});
        slide.addText('EL CARMEN · TELEMÁTICA EDUCATIVA v5',{x,y:y+CH-0.14,w:CW,h:0.14,fontSize:4.5,bold:true,color:'FFFFFF',align:'center',fontFace:'Arial'});
      });
    }
    const g=EC.alumnos[0]?.grado||'X', s=EC.alumnos[0]?.seccion||'X';
    const fileName=`Carnets_${g}${s}.pptx`;

    // Obtener blob del PPTX para descarga compatible con todos los dispositivos
    const blob = await pptx.write({outputType:'blob'});

    // iOS Safari: usar Web Share API (compartir archivo a Keynote, Drive, etc.)
    const esIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !window.MSStream;
    if(esIOS){
      try {
        const file = new File([blob], fileName, {
          type: 'application/vnd.openxmlformats-officedocument.presentationml.presentation'
        });
        if(navigator.canShare && navigator.canShare({files:[file]})){
          await navigator.share({files:[file], title:'Carnets El Carmen'});
          toast(`✅ PPTX listo — ${totalPags} páginas, ${EC.alumnos.length} carnets`,'ok');
          audit('PPTX compartido via Web Share API (iOS)','OK');
          return; // salir del try aquí — el finally activa el botón
        }
      } catch(shareErr){
        if(shareErr.name!=='AbortError')
          toast('Comparte el archivo manualmente desde tu carpeta de Descargas','info',6000);
      }
    }

    // Android, PC, y fallback iOS: descarga directa via Blob URL
    const url = URL.createObjectURL(blob);
    const a   = document.createElement('a');
    a.href     = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 8000);

    toast(`✅ PPTX generado: ${totalPags} páginas, ${EC.alumnos.length} carnets`,'ok');
    audit('PPTX carnets exportado','OK');
  } catch(err){
    toast('⚠️ Error PPTX: '+err.message,'err',7000);
    audit('Error PPTX: '+err.message,'ERROR');
  } finally {
    if(btn){ btn.textContent='📑 Carnets PPTX'; btn.disabled=false; }
  }
}

/* ══════════════════════════════════════════════
   MÓDULO 26: NAVEGACIÓN entre páginas
   ══════════════════════════════════════════════ */
function showPage(name) {
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.nb-tab').forEach(t=>t.classList.remove('active'));
  const pg=document.getElementById('page-'+name);
  const tb=document.getElementById('tab-'+name);
  if(pg) pg.classList.add('active');
  if(tb) tb.classList.add('active');
  // Detener escáner al salir del lector
  if(name!=='lector' && EC.scanActivo) detenerScanner();
  // Renderizar la página correcta
  if(name==='registro') { renderTablaGlobal(); actualizarContadores(); }
  if(name==='dashboard') renderDashboard();
}

function cerrarModal(id) {
  const m=document.getElementById(id);
  if(m) m.classList.add('hidden');
}

/* ══════════════════════════════════════════════
   MÓDULO 27: INIT async — arranque del sistema
   ══════════════════════════════════════════════ */
(async function init() {
  // Detectar HTTPS
  const noHttps = location.protocol!=='https:' && location.hostname!=='localhost' && location.hostname!=='127.0.0.1';
  if(noHttps) {
    const ah=document.getElementById('alertHttps');
    if(ah) ah.classList.remove('hidden');
  }
  // Cargar lista del plantel (persiste todo el año escolar)
  const listaGuardada = cargarListaGuardada();
  if(listaGuardada?.alumnos?.length) {
    EC.alumnos = listaGuardada.alumnos;
    EC.alumnos.forEach(a => { if(EC.histRetardos[a.id]===undefined) EC.histRetardos[a.id]=0; });
    const em = document.getElementById('excelMsg');
    if(em) em.textContent = `📋 Lista guardada · ${EC.alumnos.length} alumnos · Cargada el ${listaGuardada.fecha}`;
    document.getElementById('excelPreview')?.classList.remove('hidden');
    document.getElementById('uploadZone')?.style.setProperty('display','none');
    renderPreviewExcel();
    renderTablaGlobal(); actualizarContadores();
    audit(`Lista restaurada: ${EC.alumnos.length} alumnos`, 'OK');
  }
  // Restaurar historial de retardos si existe sesión previa
  const sesGuardada = await cargarSesion();
  if(sesGuardada?.retardos) Object.assign(EC.histRetardos, sesGuardada.retardos);
  // Inicializar status bar con fecha actual
  actualizarStatusBar();
  const sbF=document.getElementById('sbFecha');
  if(sbF) sbF.textContent = '';
  audit('Sistema El Carmen v5 iniciado', 'INFO');
})();
